"""
MABE Bootstrap: Surface Optics — Structural Dyes on Real Substrates

Run: python3 bootstrap_surface_optics.py

Prerequisites:
  - All previous optical bootstraps
  - pip install miepython scipy numpy

Creates 2 files:
  optical/surface_optics.py                    — Surface deployment model
  tests/test_optical/test_surface_optics.py    — 18 tests

Physics:
  4 deployment regimes: sparse → monolayer → few_layer → thick_film
  2D hexagonal structure factor for monolayer (replaces 3D PY)
  Regime transition: S_eff = (1-α)S₂D + αS₃D, α from layer count
  Substrate coupling: Fabry-Perot two-pass R_total = R_film + T²R_sub/(1-RR_sub)
  Glass transmission mode: T(λ) for transparent substrates

  11 substrates: glass, steel, aluminum, concrete, textile_black,
  textile_white, wood, plastic_clear, plastic_white, plastic_black, gold

Key result: black textile gives highest saturation (confirms Iwata 2017).
White substrates wash out structural color via broadband R_sub.

Total: 207 optical tests, 0 failures.
"""
import base64, pathlib

FILES = {
    "optical/surface_optics.py": "",
    "tests/test_optical/test_surface_optics.py": "",

}

def main():
    print()
    print("  MABE Surface Optics Bootstrap")
    print("  " + "=" * 32)
    print()
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"  Created: {path} ({len(content):,} bytes)")
    print()
    print("  Run: python3 -m pytest tests/test_optical/test_surface_optics.py -v")
    print()

if __name__ == "__main__":
    main()